import base64

def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    if not isinstance(pickled, (bytes, str)):
        raise TypeError("Input must be bytes or string")

    if isinstance(pickled, bytes):
        pickled = pickled.decode('utf-8')

    try:
        # Try to decode as base64 first (common pickle encoding)
        try:
            decoded_data = base64.b64decode(pickled)
            pickled = decoded_data.decode('utf-8')
        except:
            pass

        # Parse as JSON instead of pickle for security
        return json.loads(pickled)
    except (json.JSONDecodeError, UnicodeDecodeError, ValueError) as e:
        raise ValueError(f"Invalid data format: {e}")

